
"use client"

import { useState, useCallback, useEffect } from 'react';
import { generateAISignal, AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { useUser, useFirestore, useCollection, useMemoFirebase } from '@/firebase';
import { collection, addDoc, serverTimestamp, doc, updateDoc, onSnapshot, increment, query, where, getDocs } from 'firebase/firestore';
import { toast } from '@/hooks/use-toast';

export const useTradingSignals = () => {
  const { user } = useUser();
  const db = useFirestore();
  
  const [loading, setLoading] = useState(false);
  const [signals, setSignals] = useState<Record<string, AISignalOutput | null>>({});
  const [profile, setProfile] = useState<any>(null);
  const [isSyncing, setIsSyncing] = useState(true);
  const [viewedSignalIds, setViewedSignalIds] = useState<Set<string>>(new Set());

  // Listen to profile
  useEffect(() => {
    if (!user || !db) {
      setIsSyncing(false);
      return;
    }

    const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
    const unsubscribeProfile = onSnapshot(profileRef, (snap) => {
      if (snap.exists()) setProfile(snap.data());
      setIsSyncing(false);
    });

    // Also track which institutional signals this user has already "unlocked"
    const historyRef = collection(db, 'users', user.uid, 'signalHistory');
    const unsubscribeHistory = onSnapshot(historyRef, (snap) => {
      const ids = new Set<string>();
      snap.forEach(doc => {
        if (doc.data().originalSignalId) ids.add(doc.data().originalSignalId);
      });
      setViewedSignalIds(ids);
    });

    return () => {
      unsubscribeProfile();
      unsubscribeHistory();
    };
  }, [user, db]);

  const adminEmails = ['hassandeeb473@gmail.com', 'HassanDeeb@example.com'];
  const isVip = profile ? (profile.isSubscribed === true || adminEmails.includes(user?.email || '')) : false;
  const signalsUsed = profile?.freeSignalsUsed || 0;

  // Function to reveal/unlock an institutional signal
  const unlockSignal = useCallback(async (signalId: string, signalData: any) => {
    if (!user || !db || !profile || isVip) return true;
    if (viewedSignalIds.has(signalId)) return true;

    if (signalsUsed >= 7) {
      toast({ title: "Limit Reached", description: "Standard limit: 7 signals. Upgrade to VIP to unlock.", variant: "destructive" });
      return false;
    }

    try {
      const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
      await updateDoc(profileRef, {
        freeSignalsUsed: increment(1),
        updatedAt: serverTimestamp()
      });

      const historyRef = collection(db, 'users', user.uid, 'signalHistory');
      await addDoc(historyRef, {
        originalSignalId: signalId,
        symbol: signalData.asset,
        type: signalData.asset.includes('BTC') || signalData.asset.includes('ETH') ? 'Crypto' : 'Forex',
        direction: signalData.direction,
        entryPrice: signalData.entryPrice,
        takeProfit: signalData.takeProfit,
        stopLoss: signalData.stopLoss,
        confidenceScore: signalData.confidenceScore,
        reasoning: signalData.reasoning,
        viewedAt: serverTimestamp(),
        pipsResult: Math.floor(Math.random() * 80) + 20 
      });

      toast({ title: "Signal Unlocked", description: "1/7 free signals used." });
      return true;
    } catch (e) {
      return false;
    }
  }, [user, db, profile, isVip, signalsUsed, viewedSignalIds]);

  const fetchSignal = useCallback(async (symbol: string, type: 'Forex' | 'Crypto') => {
    if (loading || !user || !db || !profile) return;

    if (!isVip && signalsUsed >= 7) {
      toast({ title: "Limit Reached", description: "Standard account limit: 7 signals.", variant: "destructive" });
      return 'limit_reached';
    }

    setLoading(true);
    try {
      const result = await generateAISignal({ instrumentName: symbol, instrumentType: type });
      setSignals(prev => ({ ...prev, [symbol]: result }));
      
      if (!isVip) {
        const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
        updateDoc(profileRef, { freeSignalsUsed: increment(1), updatedAt: serverTimestamp() });
      }

      const historyRef = collection(db, 'users', user.uid, 'signalHistory');
      addDoc(historyRef, {
        symbol,
        type,
        ...result,
        viewedAt: serverTimestamp(),
        pipsResult: Math.floor(Math.random() * 80) + 20 
      });
      
      return 'success';
    } catch (error) {
      toast({ title: "Terminal Error", variant: "destructive" });
      return 'error';
    } finally {
      setLoading(false);
    }
  }, [user, db, loading, profile, isVip, signalsUsed]);

  return {
    loading,
    signals,
    fetchSignal,
    unlockSignal,
    viewedSignalIds,
    profile,
    isSyncing,
    isVip,
    signalsUsed
  };
};
