
"use client"

import React, { useEffect, useRef, memo } from 'react';
import { TrendingUp, TrendingDown, Info, Lock, Eye } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { cn } from '@/lib/utils';

interface SignalCardProps {
  symbol: string;
  type: 'Forex' | 'Crypto';
  signal: AISignalOutput;
  isLocked?: boolean;
  onUnlock?: () => void;
  onUpgradeClick?: () => void;
}

export const SignalCard = memo(({ symbol, type, signal, isLocked, onUnlock, onUpgradeClick }: SignalCardProps) => {
  const isBuy = signal.direction === 'Buy';
  const containerRef = useRef<HTMLDivElement>(null);
  
  useEffect(() => {
    if (!containerRef.current || isLocked) return;
    
    const widgetId = `tv_widget_${symbol.replace('/', '_')}`;
    const container = containerRef.current;
    container.innerHTML = `<div id="${widgetId}" class="h-full"></div>`;

    const script = document.createElement("script");
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-technical-analysis.js";
    script.type = "text/javascript";
    script.async = true;
    script.innerHTML = JSON.stringify({
      "interval": "1h",
      "width": "100%",
      "isTransparent": true,
      "height": "100%",
      "symbol": type === 'Forex' ? `FX:${symbol.replace('/', '')}` : `BINANCE:${symbol}USDT`,
      "showIntervalTabs": false,
      "displayMode": "single",
      "locale": "en",
      "colorTheme": "dark"
    });
    
    container.appendChild(script);

    return () => {
      if (container) container.innerHTML = "";
    };
  }, [symbol, type, isLocked]);
  
  return (
    <Card className={cn(
      "relative overflow-hidden border-white/5 bg-[#121212]/40 glassmorphism transition-all duration-300 rounded-3xl",
      isLocked && "min-h-[400px]"
    )}>
      <div className={`absolute top-0 left-0 w-1.5 h-full ${isBuy ? 'bg-success' : 'bg-destructive'}`} />
      
      <CardHeader className="flex flex-row items-center justify-between pb-2 px-6 pt-6">
        <div className="space-y-1">
          <CardTitle className="text-xl font-black flex items-center gap-2 tracking-tighter">
            {symbol}
            <Badge variant="outline" className="text-[8px] uppercase font-black bg-white/5">{type}</Badge>
          </CardTitle>
          <p className="text-[8px] text-muted-foreground/40 uppercase tracking-widest font-black">Institutional Sentiment</p>
        </div>
        {!isLocked && (
          <div className={cn(
            "flex items-center gap-2 font-black text-xl tracking-tighter transition-all",
            isBuy ? 'text-success' : 'text-destructive'
          )}>
            {isBuy ? <TrendingUp className="h-5 w-5" /> : <TrendingDown className="h-5 w-5" />}
            {signal.direction.toUpperCase()}
          </div>
        )}
      </CardHeader>

      <CardContent className="space-y-6 p-6 pt-2 relative">
        {isLocked ? (
          <div className="absolute inset-0 z-10 flex flex-col items-center justify-center p-8 text-center bg-black/60 backdrop-blur-xl space-y-6">
            <div className="h-20 w-20 rounded-[2rem] bg-primary/10 border border-primary/30 flex items-center justify-center">
              <Lock className="h-10 w-10 text-primary" />
            </div>
            <div className="space-y-2">
              <h3 className="text-xl font-black uppercase tracking-tighter text-white">Institutional Signal</h3>
              <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest max-w-[200px]">
                Costs 1/7 Free Credits to Reveal Details
              </p>
            </div>
            <div className="flex flex-col gap-3 w-full">
              <Button onClick={onUnlock} className="h-12 w-full bg-primary text-black font-black uppercase text-[10px] tracking-widest rounded-xl">
                <Eye className="h-4 w-4 mr-2" /> Reveal Details
              </Button>
              <Button onClick={onUpgradeClick} variant="ghost" className="text-amber-500 font-black uppercase text-[8px] tracking-[0.2em]">
                Unlimited Access? Upgrade to VIP
              </Button>
            </div>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-3 gap-4 p-4 rounded-2xl bg-black/40 border border-white/5">
              <div>
                <p className="text-[8px] text-muted-foreground uppercase font-black tracking-widest mb-1">Entry</p>
                <p className="text-xs font-mono font-bold">{signal.entryPrice.toLocaleString()}</p>
              </div>
              <div className="border-x border-white/5 px-4 text-center">
                <p className="text-[8px] text-accent uppercase font-black tracking-widest mb-1">TP</p>
                <p className="text-xs font-mono font-bold text-accent">{signal.takeProfit.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[8px] text-destructive uppercase font-black tracking-widest mb-1">SL</p>
                <p className="text-xs font-mono font-bold text-destructive">{signal.stopLoss.toLocaleString()}</p>
              </div>
            </div>

            <div className="h-40 border border-white/5 rounded-2xl bg-black/60 p-1" ref={containerRef} />

            <div className="space-y-2">
              <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest">
                <span className="text-muted-foreground">Analyst Confidence</span>
                <span className="text-primary">{signal.confidenceScore}%</span>
              </div>
              <div className="h-1 w-full bg-white/5 rounded-full overflow-hidden">
                <div className="h-full bg-primary" style={{ width: `${signal.confidenceScore}%` }} />
              </div>
            </div>

            <div className="rounded-xl bg-white/5 p-4 text-[10px] text-muted-foreground leading-relaxed italic border border-white/5">
              <Info className="h-3 w-3 inline mr-2 text-primary" />
              {signal.reasoning}
            </div>
          </>
        )}
      </CardContent>
    </Card>
  );
});
SignalCard.displayName = 'SignalCard';
