
"use client"

import React, { useEffect, useMemo, memo, useState, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import dynamic from 'next/dynamic';
import { 
  LayoutDashboard, 
  LineChart, 
  LogOut, 
  Activity,
  PieChart,
  User,
  Newspaper,
  History,
  TrendingUp,
  Lock,
  Crown,
  Zap,
  Globe,
  Radio,
  Loader2,
  Search,
  RefreshCw,
  Eye
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { WhatsAppButton } from '@/components/WhatsAppButton';
import { SignalCard } from '@/components/SignalCard';
import { Paywall } from '@/components/Paywall';
import { AdminPanel } from '@/components/AdminPanel';
import { useTradingSignals } from '@/hooks/use-trading-signals';
import { useUser, useAuth, useFirestore, useCollection, useMemoFirebase } from '@/firebase';
import { query, collection, orderBy, limit, addDoc, serverTimestamp } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { cn } from '@/lib/utils';

const EconomicCalendar = dynamic(() => import('@/components/tradingview/EconomicCalendar').then(mod => mod.EconomicCalendar), { ssr: false });
const TechnicalAnalysis = dynamic(() => import('@/components/tradingview/TechnicalAnalysis').then(mod => mod.TechnicalAnalysis), { ssr: false });
const NewsTimeline = dynamic(() => import('@/components/tradingview/NewsTimeline').then(mod => mod.NewsTimeline), { ssr: false });

export default function DashboardPage() {
  const router = useRouter();
  const auth = useAuth();
  const db = useFirestore();
  const { user, isUserLoading } = useUser();
  const { 
    signals, 
    fetchSignal, 
    unlockSignal,
    viewedSignalIds,
    loading,
    isVip,
    signalsUsed,
    isSyncing
  } = useTradingSignals();
  
  const [paywallOpen, setPaywallOpen] = useState(false);
  const [activeSymbol, setActiveSymbol] = useState('OANDA:XAUUSD');
  const [searchInput, setSearchInput] = useState('');
  const [refreshKey, setRefreshKey] = useState(0);
  const [logoClicks, setLogoClicks] = useState(0);
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  // Institutional Feed Query
  const liveSignalsQuery = useMemoFirebase(() => {
    if (!db || !user) return null;
    return query(collection(db, 'tradingSignals'), orderBy('createdAt', 'desc'), limit(4));
  }, [db, user]);

  const { data: liveSignals, isLoading: liveSignalsLoading } = useCollection(liveSignalsQuery);

  useEffect(() => {
    if (!isUserLoading && !user) router.replace('/login');
  }, [user, isUserLoading, router]);

  // AUTOMATED SEEDER FOR ADMIN
  useEffect(() => {
    const adminEmails = ['hassandeeb473@gmail.com', 'HassanDeeb@example.com'];
    if (!user || !adminEmails.includes(user.email || '') || !db) return;

    const seedAnalystData = async () => {
      console.log("[ADMIN] Triggering automatic Analyst Feed seed...");
      const mockSignals = [
        { asset: 'XAUUSD', direction: 'Buy', entry: 2025.20, tp: 2045.00, sl: 2010.00, reason: 'Demand at key Fibonacci level (H4).' },
        { asset: 'BTCUSD', direction: 'Sell', entry: 51200, tp: 48500, sl: 53000, reason: 'RSI divergence detected on 4-hour chart.' },
        { asset: 'EURUSD', direction: 'Buy', entry: 1.0850, tp: 1.0950, sl: 1.0800, reason: 'ECB hawkish sentiment favoring Euro.' }
      ];
      try {
        for (const sig of mockSignals) {
          await addDoc(collection(db, 'tradingSignals'), {
            ...sig,
            entryPrice: sig.entry,
            takeProfit: sig.tp,
            stopLoss: sig.sl,
            reasoning: sig.reason,
            confidenceScore: 94,
            createdAt: serverTimestamp(),
            isLive: true
          });
        }
      } catch (e) {
        console.error("[ADMIN] Seeding failed:", e);
      }
    };

    // Run every 15 minutes (900,000 ms)
    const interval = setInterval(seedAnalystData, 900000);
    return () => clearInterval(interval);
  }, [user, db]);

  const instruments = useMemo(() => [
    { symbol: 'GOLD', name: 'Gold Spot', type: 'Forex' as const },
    { symbol: 'EUR/USD', name: 'Euro / USD', type: 'Forex' as const },
    { symbol: 'BTC', name: 'Bitcoin', type: 'Crypto' as const },
    { symbol: 'ETH', name: 'Ethereum', type: 'Crypto' as const },
  ], []);

  const handleFetch = async (symbol: string, type: 'Forex' | 'Crypto') => {
    const status = await fetchSignal(symbol, type);
    if (status === 'limit_reached') setPaywallOpen(true);
  };

  const handleUnlockLiveSignal = async (id: string, data: any) => {
    const success = await unlockSignal(id, data);
    if (!success) setPaywallOpen(true);
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchInput) return;
    const formatted = searchInput.includes(':') ? searchInput.toUpperCase() : `OANDA:${searchInput.toUpperCase()}`;
    setActiveSymbol(formatted);
  };

  const handleLogout = async () => {
    await signOut(auth);
    router.replace('/');
  };

  const triggerRefresh = () => setRefreshKey(prev => prev + 1);

  const handleLogoClick = () => {
    const nextClicks = logoClicks + 1;
    if (nextClicks >= 7) {
      setIsAdminOpen(true);
      setLogoClicks(0);
    } else {
      setLogoClicks(nextClicks);
    }
  };

  if (isUserLoading || isSyncing || !user) return (
    <div className="min-h-screen bg-black flex items-center justify-center">
      <Activity className="h-8 w-8 text-primary animate-spin" />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#020617] text-foreground flex">
      {/* Sidebar Terminal */}
      <aside className="w-64 border-r border-white/5 bg-black/40 backdrop-blur-xl hidden lg:flex flex-col sticky top-0 h-screen">
        <div className="p-6">
          <div 
            onClick={handleLogoClick}
            className="flex items-center gap-2 text-lg font-black tracking-tighter cursor-pointer select-none group"
          >
            <LineChart className="h-6 w-6 text-primary group-hover:scale-110 transition-transform" />
            DEEBDATA <span className="text-primary">TRADING</span>
          </div>
        </div>
        
        <nav className="flex-1 px-4 space-y-1">
          <NavItem href="/dashboard" icon={<LayoutDashboard className="h-4 w-4" />} label="Terminal" active />
          <NavItem href="/analysis" icon={<PieChart className="h-4 w-4" />} label="Technical Hub" />
          <NavItem href="/history" icon={<History className="h-4 w-4" />} label="Execution Log" />
          <NavItem href="/news" icon={<Newspaper className="h-4 w-4" />} label="Global News" />
          <NavItem href="/profile" icon={<User className="h-4 w-4" />} label="Identity" />
        </nav>

        {!isVip && (
          <div className="px-4 py-6">
            <Button onClick={() => setPaywallOpen(true)} className="w-full h-12 bg-amber-500 hover:bg-amber-600 text-black font-black uppercase text-[10px] tracking-widest rounded-xl animate-pulse-gold">
              <Crown className="h-4 w-4 mr-2" /> Upgrade to VIP
            </Button>
          </div>
        )}

        <div className="p-4 border-t border-white/5 text-center">
          <p className="text-[10px] text-muted-foreground/40 font-bold uppercase tracking-[0.2em]">Hassan Deeb Terminal</p>
        </div>

        <div className="p-4 border-t border-white/5">
          <Button variant="ghost" className="w-full justify-start gap-3 text-muted-foreground hover:text-destructive" onClick={handleLogout}>
            <LogOut className="h-4 w-4" /> Log Out
          </Button>
        </div>
      </aside>

      {/* Main Terminal Core */}
      <main className="flex-1 bg-black/20 overflow-y-auto">
        <header className="h-16 border-b border-white/5 flex items-center justify-between px-8 bg-black/40 backdrop-blur-md sticky top-0 z-40">
          <div className="flex items-center gap-6">
            <h1 className="text-sm font-black uppercase tracking-widest hidden sm:block">Market Control</h1>
            
            <form onSubmit={handleSearch} className="relative w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3 w-3 text-muted-foreground" />
              <Input 
                placeholder="Search Asset (e.g. BTCUSD)" 
                className="h-9 bg-white/5 border-white/10 pl-9 text-[10px] font-bold uppercase tracking-widest"
                value={searchInput}
                onChange={(e) => setSearchInput(e.target.value)}
              />
            </form>

            {!isVip ? (
              <Badge variant="outline" className="text-[9px] font-black uppercase border-white/10 text-amber-500">
                Free Member ({signalsUsed}/7 Used)
              </Badge>
            ) : (
              <Badge variant="outline" className="text-[9px] font-black uppercase border-amber-500/20 text-amber-500 bg-amber-500/5">
                VIP Member
              </Badge>
            )}
          </div>
          <div className="flex items-center gap-4">
            <Button onClick={triggerRefresh} variant="ghost" size="sm" className="h-8 text-[9px] font-black uppercase tracking-widest">
              <RefreshCw className={cn("h-3 w-3 mr-2", refreshKey > 0 && "animate-spin")} /> Global Refresh
            </Button>
            <Badge variant="outline" className="bg-success/5 border-success/20 text-success text-[10px] uppercase font-black px-3 py-1 hidden sm:flex">
              <Activity className="h-3 w-3 mr-2 animate-pulse" /> Institutional Live
            </Badge>
          </div>
        </header>

        <div className="p-8 space-y-8">
          <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
            <div className="xl:col-span-3 space-y-12">
              
              {/* TOP ANALYST SIGNALS SECTION */}
              <section className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-xl font-black tracking-tighter uppercase flex items-center gap-2">
                    <Globe className="h-5 w-5 text-accent animate-spin-slow" /> 
                    Top Analyst Live Signals
                  </h2>
                  <div className="flex items-center gap-3">
                    <Button variant="ghost" size="sm" onClick={triggerRefresh} className="h-7 w-7 p-0 rounded-full">
                      <RefreshCw className="h-3 w-3" />
                    </Button>
                    <Badge className="bg-accent/10 text-accent border-accent/20 text-[8px] font-black uppercase px-2">Institutional Broadcast</Badge>
                  </div>
                </div>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6" key={`analyst-${refreshKey}`}>
                  {liveSignalsLoading && (
                    <div className="col-span-2 py-10 flex items-center justify-center">
                      <Loader2 className="h-6 w-6 text-primary animate-spin" />
                    </div>
                  )}
                  {liveSignals?.map((sig) => (
                    <SignalCard 
                      key={sig.id}
                      symbol={sig.asset}
                      type={sig.asset.includes('BTC') || sig.asset.includes('ETH') ? 'Crypto' : 'Forex'}
                      signal={{
                        direction: sig.direction,
                        entryPrice: sig.entryPrice,
                        takeProfit: sig.takeProfit,
                        stopLoss: sig.stopLoss,
                        confidenceScore: sig.confidenceScore,
                        reasoning: sig.reasoning
                      }}
                      isLocked={!isVip && !viewedSignalIds.has(sig.id)}
                      onUnlock={() => handleUnlockLiveSignal(sig.id, sig)}
                      onUpgradeClick={() => setPaywallOpen(true)}
                    />
                  ))}
                  {(liveSignals?.length === 0 && !liveSignalsLoading) && (
                    <div className="col-span-2 py-10 border border-dashed border-white/5 rounded-3xl flex flex-col items-center justify-center text-center bg-white/5">
                      <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Waiting for live institutional broadcast...</p>
                    </div>
                  )}
                </div>
              </section>

              {/* AI PULSE SIGNALS SECTION */}
              <section className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-2xl font-black tracking-tighter uppercase">AI Pulse Signals</h2>
                  <div className="flex gap-2">
                    {instruments.map(inst => (
                      <Button 
                        key={inst.symbol} 
                        variant="outline" 
                        size="sm" 
                        className="h-8 text-[9px] font-black uppercase tracking-widest bg-white/5" 
                        onClick={() => handleFetch(inst.symbol, inst.type)}
                        disabled={loading}
                      >
                        {inst.symbol}
                      </Button>
                    ))}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {Object.entries(signals).map(([symbol, signal]) => (
                    signal && (
                      <SignalCard 
                        key={`${symbol}-${refreshKey}`}
                        symbol={symbol}
                        type={instruments.find(i => i.symbol === symbol)?.type || 'Forex'}
                        signal={signal}
                        isLocked={false} // Already deducted on generation
                        onUpgradeClick={() => setPaywallOpen(true)}
                      />
                    )
                  ))}
                  {Object.keys(signals).length === 0 && !loading && (
                    <div className="col-span-2 py-20 border border-dashed border-white/10 rounded-3xl flex flex-col items-center justify-center text-center">
                      <TrendingUp className="h-10 w-10 text-muted-foreground/20 mb-4" />
                      <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Select instrument to generate AI signals (Costs 1 Credit)</p>
                    </div>
                  )}
                </div>
              </section>

              {/* Technical Analysis Section */}
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h3 className="text-sm font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                    <Zap className="h-4 w-4 text-primary" /> Market Sentiment Tracker: {activeSymbol.split(':').pop()}
                  </h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6" key={`tech-${refreshKey}`}>
                  <div className="bg-white/5 rounded-3xl border border-white/5 p-6 space-y-4">
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-center text-muted-foreground">Focus: {activeSymbol.split(':').pop()}</p>
                    <TechnicalAnalysis symbol={activeSymbol} height={320} />
                  </div>
                  <div className="bg-white/5 rounded-3xl border border-white/5 p-6 space-y-4">
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-center text-muted-foreground">BTC/USD Global</p>
                    <TechnicalAnalysis symbol="BITSTAMP:BTCUSD" height={320} />
                  </div>
                </div>
              </div>
            </div>

            {/* Sidebar Widgets */}
            <div className="space-y-8">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="text-xs font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                     <Newspaper className="h-4 w-4 text-accent" /> Live Intelligence
                  </h3>
                </div>
                <div className="rounded-3xl border border-white/5 glassmorphism overflow-hidden min-h-[500px]" key={`news-${refreshKey}`}>
                  <NewsTimeline height={600} />
                </div>
              </div>
              
              <div className={cn("rounded-3xl border border-white/5 glassmorphism overflow-hidden relative", !isVip && "opacity-50 grayscale pointer-events-none")}>
                {!isVip && (
                  <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/40 backdrop-blur-sm">
                    <Button onClick={() => setPaywallOpen(true)} variant="outline" className="font-black uppercase text-[10px] tracking-widest border-amber-500/50 text-amber-500">
                      <Lock className="h-3 w-3 mr-2" /> Unlock Calendar
                    </Button>
                  </div>
                )}
                <EconomicCalendar />
              </div>
            </div>
          </div>
        </div>
      </main>

      <AdminPanel isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      <Paywall isOpen={paywallOpen} onClose={() => setPaywallOpen(false)} />
      <WhatsAppButton />

      <style jsx global>{`
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 8s linear infinite;
        }
      `}</style>
    </div>
  );
}

const NavItem = memo(({ href, icon, label, active, locked }: { href: string, icon: React.ReactNode, label: string, active?: boolean, locked?: boolean }) => (
  <Link 
    href={locked ? "#" : href} 
    className={cn(
      "flex items-center justify-between px-4 py-2 rounded-xl transition-all",
      active ? 'bg-primary/10 text-primary font-bold' : 'text-muted-foreground hover:bg-white/5 hover:text-white',
      locked && "opacity-50 cursor-not-allowed"
    )}
  >
    <div className="flex items-center gap-3">
      {icon} <span className="text-sm">{label}</span>
    </div>
    {locked && <Lock className="h-3 w-3" />}
  </Link>
));
NavItem.displayName = 'NavItem';
